internal fun strWidth(s: String): Int {
    var sum = 0
    var nextInfo = WidthInfo.DEFAULT
    var i = s.length
    while (i > 0) {
        i--
        val low = s[i]
        val cp: Int = if (low.isLowSurrogate() && i > 0 && s[i - 1].isHighSurrogate()) {
            i--
            ((s[i].code - 0xD800) shl 10) + (low.code - 0xDC00) + 0x10000
        } else {
            low.code
        }
        val (add, info) = widthInStr(cp, nextInfo)
        sum += add
        nextInfo = info
    }
    return sum
}

